Union-Find (DSU).code:
struct DSU {
    vector<int> p;
    DSU(int n) {
        p.resize(n);
        iota(p.begin(), p.end(), 0); // [GOTCHA] Initialize with 0 ~ n-1
    }
    int find(int i) {
        // [GOTCHA] Path Compression is mandatory for O(α(N))
        return p[i] == i ? i : (p[i] = find(p[i]));
    }
    void unite(int i, int j) {
        int root_i = find(i), root_j = find(j);
        if (root_i != root_j) p[root_i] = root_j;
    }
};

