long long memo[20][2][2][state];
long long dfs(int pos, bool limit, bool lead, int s, string& num) {
    if (pos == num.size()) return 1;
    if (memo[pos][limit][lead][s] != -1) return memo[pos][limit][lead][s];

    int up = limit ? num[pos] - '0' : 9;
    long long res = 0;
    for (int i = 0; i <= up; i++) {
        // [GOTCHA] 1. Correctly propagate the 'limit' flag
        // [GOTCHA] 2. Handle 'lead zero' if it affects the digit state
        res += dfs(pos + 1, limit && (i == up), lead && (i == 0), next_s, num);
    }
    return memo[pos][limit][lead][s] = res;
}

